const BACKEND_ORIGIN = "https://api.backend.example.com";

const ALLOWED_ORIGINS = [
  "https://app.example.com",
  "https://staging.example.com",
  "http://localhost:3000",
  "http://localhost:5173",
];

function getAllowedOrigin(request) {
  const origin = request.headers.get("Origin");
  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    return origin;
  }
  return null;
}

function buildCorsHeaders(request) {
  const allowedOrigin = getAllowedOrigin(request);
  if (!allowedOrigin) {
    return {};
  }
  return {
    "Access-Control-Allow-Origin": allowedOrigin,
    "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, PATCH, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With",
    "Access-Control-Allow-Credentials": "true",
    "Access-Control-Max-Age": "86400",
    "Vary": "Origin",
  };
}

function handlePreflightRequest(request) {
  const allowedOrigin = getAllowedOrigin(request);
  if (!allowedOrigin) {
    return new Response(null, { status: 403 });
  }
  return new Response(null, {
    status: 204,
    headers: buildCorsHeaders(request),
  });
}

async function handleProxyRequest(request) {
  const url = new URL(request.url);
  const backendUrl = new URL(url.pathname + url.search, BACKEND_ORIGIN);

  const sanitizedHeaders = new Headers();
  const allowedRequestHeaders = [
    "content-type",
    "authorization",
    "x-requested-with",
    "accept",
    "accept-language",
  ];

  for (const headerName of allowedRequestHeaders) {
    const value = request.headers.get(headerName);
    if (value) {
      sanitizedHeaders.set(headerName, value);
    }
  }

  sanitizedHeaders.set("X-Forwarded-For", request.headers.get("CF-Connecting-IP") || "unknown");
  sanitizedHeaders.set("X-Forwarded-Host", url.hostname);
  sanitizedHeaders.set("X-Forwarded-Proto", url.protocol.replace(":", ""));

  const modifiedRequest = new Request(backendUrl.toString(), {
    method: request.method,
    headers: sanitizedHeaders,
    body: ["GET", "HEAD"].includes(request.method) ? null : request.body,
    redirect: "manual",
  });

  try {
    const response = await fetch(modifiedRequest);

    const responseHeaders = new Headers(response.headers);

    const corsHeaders = buildCorsHeaders(request);
    for (const [key, value] of Object.entries(corsHeaders)) {
      responseHeaders.set(key, value);
    }

    responseHeaders.set("X-Content-Type-Options", "nosniff");
    responseHeaders.set("X-Frame-Options", "DENY");
    responseHeaders.set("Referrer-Policy", "strict-origin-when-cross-origin");

    responseHeaders.delete("Server");
    responseHeaders.delete("X-Powered-By");

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: responseHeaders,
    });
  } catch (error) {
    return new Response(JSON.stringify({ error: "Bad Gateway", message: "Failed to reach backend service" }), {
      status: 502,
      headers: {
        "Content-Type": "application/json",
        ...buildCorsHeaders(request),
      },
    });
  }
}

export default {
  async fetch(request, env, ctx) {
    if (request.method === "OPTIONS") {
      return handlePreflightRequest(request);
    }

    const allowedOrigin = getAllowedOrigin(request);
    const origin = request.headers.get("Origin");
    if (origin && !allowedOrigin) {
      return new Response(JSON.stringify({ error: "Forbidden", message: "Origin not allowed" }), {
        status: 403,
        headers: { "Content-Type": "application/json" },
      });
    }

    const allowedMethods = ["GET", "POST", "PUT", "DELETE", "PATCH", "HEAD"];
    if (!allowedMethods.includes(request.method)) {
      return new Response(JSON.stringify({ error: "Method Not Allowed" }), {
        status: 405,
        headers: {
          "Content-Type": "application/json",
          "Allow": allowedMethods.join(", "),
        },
      });
    }

    return handleProxyRequest(request);
  },
};